"use strict";parserFactory.register("noveltoon.mobi",()=>new NoveltoonParser);class NoveltoonParser extends Parser{constructor(){super()}async getChapterUrls(e){return[...e.querySelectorAll("a.episodes-info-a-item")].map(e=>NoveltoonParser.ToChapterInfo(e))}static ToChapterInfo(e){let t=e.querySelector(".episode-item-num").textContent.trim()+" "+e.querySelector(".episode-item-title").textContent.trim();return{sourceUrl:e.href,title:t}}findContent(e){return e.querySelector("div.watch-chapter-detail")}extractTitleImpl(e){return e.querySelector("h1.detail-title")}extractAuthor(e){return e.querySelector("p.detail-author")?.textContent??super.extractAuthor(e)}findChapterTitle(e){return e.querySelector("p.watch-chapter-title")?.textContent}findCoverImageUrl(e){return util.getFirstImgSrc(e,"div.detail-top-right")}getInformationEpubItemChildNodes(e){return[...e.querySelectorAll("div.detail-desc")]}}